Паттерн Посредник (Mediator) используется для упрощения взаимодействия между множеством объектов. Вместо того, чтобы объекты общались друг с другом напрямую, они будут общаться через посредника, который контролирует логику взаимодействия между объектами.

Ниже приведен пример реализации паттерна Посредник на языке программирования C#.

```csharp
using System;
using System.Collections.Generic;

// Интерфейс посредника
public interface IMediator
{
    void Send(string message, Colleague colleague);
}

// Класс посредника
public class ConcreteMediator : IMediator
{
    private List<Colleague> colleagues;

    public ConcreteMediator()
    {
        colleagues = new List<Colleague>();
    }

    public void AddColleague(Colleague colleague)
    {
        colleagues.Add(colleague);
    }

    public void Send(string message, Colleague sender)
    {
        foreach (var colleague in colleagues)
        {
            if (colleague != sender)
            {
                colleague.Receive(message);
            }
        }
    }
}

// Абстрактный класс коллеги, который будет наследоваться другими объектами
public abstract class Colleague
{
    protected IMediator mediator;

    public Colleague(IMediator mediator)
    {
        this.mediator = mediator;
    }

    public virtual void Send(string message)
    {
        mediator.Send(message, this);
    }

    public abstract void Receive(string message);
}

// Конкретные коллеги
public class ConcreteColleague1 : Colleague
{
    public ConcreteColleague1(IMediator mediator) : base(mediator)
    {
    }

    public override void Receive(string message)
    {
        Console.WriteLine("Colleague1 received message: " + message);
    }
}

public class ConcreteColleague2 : Colleague
{
    public ConcreteColleague2(IMediator mediator) : base(mediator)
    {
    }

    public override void Receive(string message)
    {
        Console.WriteLine("Colleague2 received message: " + message);
    }
}

class Program
{
    static void Main(string[] args)
    {
        ConcreteMediator mediator = new ConcreteMediator();

        ConcreteColleague1 colleague1 = new ConcreteColleague1(mediator);
        ConcreteColleague2 colleague2 = new ConcreteColleague2(mediator);

        mediator.AddColleague(colleague1);
        mediator.AddColleague(colleague2);

        colleague1.Send("Hello, World!");
        colleague2.Send("Hi, there!");

        Console.ReadKey();
    }
}
```

В этом примере мы создаем интерфейс `IMediator` и конкретный посредник `ConcreteMediator`, который реализует этот интерфейс. Также создаем абстрактный класс `Colleague` и его конкретные реализации `ConcreteColleague1` и `ConcreteColleague2`. Объекты этих классов могут обмениваться сообщениями между собой через конкретный посредник `ConcreteMediator`.

