using namespace std;

// Читает файл-БД и помещает содержимое в вектор
vector<string> readDatabaseFile(const string& databaseFilePath)
{
    vector<string> virusList;
    ifstream databaseFile(databaseFilePath);
    string line;
    while (getline(databaseFile, line)) {
        virusList.push_back(line);
    }
    return virusList;
}

bool isVirus(const string& buffer, const vector<string>& virusList) 
{
    for (const string& virus : virusList) {
        if (buffer == virus) {
            return true;
        }
    }
    return false;
}

string readBufferFromFile(const string& fileName)
{
    ifstream file(fileName);
    return string((istreambuf_iterator<char>(file)), istreambuf_iterator<char>());
}

bool deleteFile(const string& fileName) {
    return remove(fileName.c_str()) == 0;
}

vector<string> getFilesInDirectory(const string& path) {
    vector<string> files;

    DIR* dir;
    struct dirent* ent;
    if ((dir = opendir(path.c_str())) != NULL) {
        while ((ent = readdir(dir)) != NULL) {
            if (ent->d_type == DT_REG) { // Только обычные файлы
                files.push_back(ent->d_name);
            }
        }
        closedir(dir);
    }

    return files;
}

void scanDirectory(const string& path, const vector<string>& virusList) {
    vector<string> files = getFilesInDirectory(path);

    for (const string& fileName : files) {
        string fullFilePath = path + "/" + fileName;
        string buffer = readBufferFromFile(fullFilePath);

        if (isVirus(buffer, virusList)) {
            cout << "Файл " << fullFilePath << " является вирусом!" << endl;
            // Предлагаем удалить файл
            if(deleteFile(fullFilePath)) {
                cout << "Файл " << fullFilePath << " удален!" << endl;
            } else {
                cout << "Ошибка при удалении файла " << fullFilePath << "!" << endl;
            }
        }
    }

    // Рекурсивный вызов для всех поддиректорий
    DIR* dir;
    struct dirent* ent;
    if ((dir = opendir(path.c_str())) != NULL) {
        while ((ent = readdir(dir)) != NULL) {
            if (ent->d_type == DT_DIR && strcmp(ent->d_name, ".") != 0 && strcmp(ent->d_name, "..") != 0) { // Только директории, кроме . и ..
                string subDirPath = path + "/" + ent->d_name;
                scanDirectory(subDirPath, virusList);
            }
        }
        closedir(dir);
    }
}

int main() {
    // Путь к директории, которую нужно просканировать
