const Cup = () => {
const {centralizeCamera, cameraDown, cameraUp, readyState, cupSubscribe, cupUnsubscribe, zoomAdd, zoomSub} = useRustWsServer();
const symbol = useSelector((state: AppState) => state.screenerSlice.symbol);
const pair = useSelector((state: AppState) => state.cupSlice.pair);
const rowCount = useSelector((state: AppState) => state.cupSlice.rowCount);
const camera = useSelector((state: AppState) => state.cupSlice.camera);
const zoom = useSelector((state: AppState) => state.cupSlice.zoom);
const cellHeight = useSelector((state: AppState) => state.cupSlice.cellHeight);
const cup: {[key: number]: CupItem} = useSelector((state: AppState) => state.cupSlice.cup);
const bestMicroPrice = useSelector((state: AppState) => state.cupSlice.bestMicroPrice);
const maxVolume = useSelector((state: AppState) => state.cupSlice.maxVolume);
const precision = useSelector((state: AppState) => state.binancePrecision.futures[symbol.toUpperCase()]);
const tickSize = useSelector((state: AppState) => state.binanceTickSize.futures[symbol.toUpperCase()]);
const [dpiScale, setDpiScale] = useState(Math.ceil(window.devicePixelRatio));
const [canvasSize, setCanvasSize] = useState<CanvasSize>({height: 0, width: 0});
const [animationFrameId, setAnimationFrameId] = useState<number|null>(null);
const [zoomedBestMicroPrice, setZoomedBestMicroPrice] = useState<BestMicroPrice|null>(null);
const containerRef = useRef<HTMLDivElement|null>(null);
const canvasRef = useRef<HTMLCanvasElement|null>(null);
const size = useComponentResizeListener(canvasRef);
const dispatch = useDispatch();
const darkMode = useTheme().palette.mode === “dark”;

const draw = useCallback(() => {
if (null === canvasRef || !precision) return;

const context = canvasRef.current?.getContext(“2d”);

if (context) {
cupDrawer.clear(context, canvasSize);
const rowsOnScreenCount = cupTools.getRowsCountOnScreen(
canvasSize.height,
cupOptions().cell.defaultHeight * dpiScale,
);
const realCellHeight = canvasSize.height / rowsOnScreenCount;

if (cellHeight !== realCellHeight) {
dispatch(setCupCellHeight(realCellHeight));
}

if (rowCount !== rowsOnScreenCount) {
dispatch(setCupRowCount(rowsOnScreenCount));

return;
}

if (camera === 0) {
centralizeCamera();

return;
}

const zoomedTickSize = parseFloat(tickSize) * Math.pow(10, precision?.price) * zoom;
const startMicroPrice = camera + rowCount / 2 * zoomedTickSize - zoomedTickSize;

for (let index = 0; index <= rowCount; index++) {
const microPrice = startMicroPrice - index * zoomedTickSize;

if (microPrice < 0) continue;

const item = !cup[microPrice]
? {
futures_price_micro: microPrice,
quantity: 0,
spot_quantity: 0,
side: microPrice <= (zoomedBestMicroPrice?.buy || 0) ? “Buy” : “Sell”,
}
: cup[microPrice];

const yPosition = realCellHeight * index;
const isBestPrice = cupTools.isBestPrice(
item.side,
item.futures_price_micro,
zoomedBestMicroPrice,
);

cupDrawer.drawCell(
context,
item,
maxVolume,
isBestPrice,
yPosition,
realCellHeight,
canvasSize.width,
dpiScale,
darkMode
);

if (isBestPrice) {
cupDrawer.drawFill(
context,
item,
maxVolume,
yPosition,
realCellHeight,
canvasSize.width,
dpiScale,
darkMode
);
}

cupDrawer.drawPrice(
context,
cupTools.microPriceToReal(item.futures_price_micro, precision.price),
item.side,
isBestPrice,
yPosition,
realCellHeight,
canvasSize.width,
dpiScale,
darkMode
);

cupDrawer.drawQuantity(
context,
cupTools.abbreviateNumber(item.quantity),
item.side,
isBestPrice,
yPosition,
realCellHeight,
canvasSize.width,
dpiScale,
darkMode
);
}
}
}, [cup, camera]);

const wheelHandler = (e: WheelEvent) => {
e.preventDefault();
e.deltaY < 0 ? cameraUp() : cameraDown();
};

useEffect(() => {
canvasRef.current?.addEventListener(“wheel”, wheelHandler, {passive: false});

return () => {
canvasRef.current?.removeEventListener(“wheel”, wheelHandler);
};
}, [camera]);

useEffect(() => {
if (bestMicroPrice && precision) {
const zoomedTickSize = parseFloat(tickSize) * Math.pow(10, precision.price) * zoom;
setZoomedBestMicroPrice({
buy: parseInt((Math.floor(bestMicroPrice.buy / zoomedTickSize) * zoomedTickSize).toFixed(0)),
sell: parseInt((Math.ceil(bestMicroPrice.sell / zoomedTickSize) * zoomedTickSize).toFixed(0)),
});
}
}, [bestMicroPrice]);

useEffect(() => {
if (null !== animationFrameId) {
cancelAnimationFrame(animationFrameId);
}

setAnimationFrameId(requestAnimationFrame(draw));
}, [cup, symbol, camera]);

useEffect(() => {
setDpiScale(Math.ceil(window.devicePixelRatio));
}, [window.devicePixelRatio]);

useEffect(() => {
if (!size) {
return;
}

setCanvasSize({
width: Math.floor(size.width) * dpiScale,
height: Math.floor(size.height) * dpiScale,
});
}, [dpiScale, size]);

useEffect(() => {
if (0 === camera) {
centralizeCamera();
}
}, [zoomedBestMicroPrice]);

useEffect(() => {
if (symbol) {
dispatch(setCupPair(symbol.toUpperCase()));
dispatch(setCupCamera(0));
}
}, [symbol]);

useEffect(() => {
if (readyState === ReadyState.OPEN && null !== pair) {
cupSubscribe(pair, camera, zoom, rowCount);
}

return () => {
if (pair != null) {
cupUnsubscribe(pair);
}
};
}, [pair, camera, zoom, rowCount, readyState]);

