        ? cupOptions(darkMode).bestBuy.fillColor
        : cupOptions(darkMode).bestSell.fillColor;

    const cornerColor = darkMode ? "#191919" : "#ffffff";

    // Draw the main rectangle without rounded corners
    ctx.beginPath();
    ctx.rect(0, yPosition, cupTools.getCellWidth(fullWidth, cupItem.quantity, maxVolume, false), cellHeight);
    ctx.fillStyle = fillColor;
